mcp:tool-listener.mcp:parameters-schema:
{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to retrieve pay plan for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"}
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to create pay plan for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"},
    "payplan": {
      "type": "object",
      "description": "Pay plan creation details",
      "properties": {
        "payplandetails": {
          "type": "object",
          "properties": {
            "accountid": {"type": "string", "description": "Account ID"},
            "comments": {"type": "string", "description": "Comments"},
            "payoraccountid": {"type": "string", "description": "Payor account ID"},
            "paymethod": {"type": "string", "description": "Payment method (e.g., MAIL)"},
            "payplanstatus": {"type": "string", "description": "Pay plan status code"},
            "payplantype": {"type": "string", "description": "Pay plan type (e.g., CIA)"},
            "startdate": {"type": "string", "description": "Start date (e.g., 2016-03-31 00:00:00)"},
            "thirdpartypayor": {"type": "string", "description": "Third party payor"},
            "thirdpartyguarantor": {"type": "string", "description": "Third party guarantor flag"},
            "user": {"type": "string", "description": "User identifier"},
            "pps": {
              "type": "object",
              "description": "Payment plan schedule",
              "properties": {
                "ppsrow": {
                  "type": "array",
                  "items": {
                    "type": "object",
                    "properties": {
                      "scheduleddate": {"type": "string", "description": "Scheduled payment date"},
                      "scheduledamount": {"type": "string", "description": "Scheduled payment amount"}
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization", "payplan"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to retrieve agency pay plan for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"}
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to retrieve recommend budget for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "newBudgetDate": {"type": "string", "description": "New budget date (e.g., 2021-03-08)"},
    "defaultFlag": {"type": "string", "description": "Default flag (default: RCBUD)"},
    "recommendBudgetSwitch": {"type": "boolean", "description": "Recommend budget switch (default: true)"},
    "budgetPlan": {"type": "string", "description": "Budget plan type (default: BPP)"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"}
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization", "newBudgetDate"]
}

http:request.http:query-params:
#[output application/java --- {
  "new-budget-date": vars.toolParams.newBudgetDate,
  "default-flag": vars.toolParams.defaultFlag default "RCBUD",
  "recommend-budget-switch": vars.toolParams.recommendBudgetSwitch default true,
  "budget-plan": vars.toolParams.budgetPlan default "BPP"
}]

mcp:tool-listener.mcp:parameters-schema:
{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to add budget for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"},
    "addbudget": {
      "type": "object",
      "description": "Add budget request body",
      "properties": {
        "transactiontype": {"type": "string", "description": "Transaction type"},
        "addbudgetservice": {
          "type": "object",
          "properties": {
            "addbudgetdetails": {
              "type": "object",
              "properties": {
                "budgetplan": {"type": "string", "description": "Budget plan code (max 8 chars)"},
                "newbudgetdate": {"type": "string", "description": "New budget date (format: date)"},
                "totalbudgetamount": {"type": "number", "description": "Total budget amount"},
                "totalnewbudget": {"type": "number", "description": "Total new budget amount"},
                "sabudget": {
                  "type": "array",
                  "description": "Service agreement budget entries",
                  "items": {
                    "type": "object",
                    "properties": {
                      "sabudgetrow": {
                        "type": "array",
                        "items": {
                          "type": "object",
                          "properties": {
                            "rowaction": {"type": "string"},
                            "serviceagreement": {"type": "string"},
                            "lastchangeddate": {"type": "string"},
                            "budgetamount": {"type": "number"},
                            "newbudget": {"type": "number"}
                          }
                        }
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization", "addbudget"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to cancel budget for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"},
    "cancelbudget": {
      "type": "object",
      "description": "Cancel budget request body",
      "properties": {
        "cancelbudgetservice": {
          "type": "object",
          "properties": {
            "cancelbudgetdetails": {
              "type": "object",
              "properties": {
                "cancel": {"type": "boolean", "description": "Cancel flag"},
                "version": {"type": "integer", "description": "Version number"},
                "newbudgetdate": {"type": "string", "description": "New budget date (format: date)"},
                "totalnewbudget": {"type": "number", "description": "Total new budget amount"}
              }
            }
          }
        }
      }
    }
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization", "cancelbudget"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to retrieve active payplan for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"}
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization"]
}

{
  "type": "object",
  "properties": {
    "payplanId": {"type": "string", "description": "The payplan ID to update or cancel"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "iscancel": {"type": "string", "description": "Whether to cancel the payplan"},
    "payplancancelreasondescription": {"type": "string", "description": "Reason description for payplan cancellation"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"}
  },
  "required": ["payplanId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization", "iscancel"]
}

{
  "type": "object",
  "properties": {
    "accountId": {"type": "string", "description": "The account ID to retrieve payplan override for"},
    "sourceSystem": {"type": "string", "description": "Source system identifier"},
    "targetSystem": {"type": "string", "description": "Target system identifier"},
    "correlationId": {"type": "string", "description": "Correlation ID for request tracking"},
    "authToken": {"type": "string", "description": "Authentication token"},
    "authorization": {"type": "string", "description": "Basic authorization header value"},
    "goodFaithPaymentDate": {"type": "string", "description": "Good faith payment date (e.g., 2016-03-31 00:00:00)"},
    "goodFaithPaymentAmount": {"type": "string", "description": "Good faith payment amount"},
    "numInstallments": {"type": "string", "description": "Number of installments"},
    "overrideType": {"type": "string", "description": "Override type (e.g., NONE)"}
  },
  "required": ["accountId", "sourceSystem", "targetSystem", "correlationId", "authToken", "authorization"]
}

http:request.http:query-params:
#[output application/java --- {
  ("goodFaithPaymentDate": vars.toolParams.goodFaithPaymentDate) if vars.toolParams.goodFaithPaymentDate?,
  ("goodFaithPaymentAmount": vars.toolParams.goodFaithPaymentAmount) if vars.toolParams.goodFaithPaymentAmount?,
  ("numInstallments": vars.toolParams.numInstallments) if vars.toolParams.numInstallments?,
  ("overrideType": vars.toolParams.overrideType) if vars.toolParams.overrideType?
}]
